import kotlinx.coroutines.flow.*
import kotlinx.coroutines.testing.*
import org.junit.Test
import kotlin.test.*
import kotlin.time.Duration.Companion.seconds

class ReproductionTest : TestBase() {
    @Test
    fun testCallbackFlowTimeoutException() = runTest {
        val flow = callbackFlow<Int> {
            close(IllegalStateException("Test Exception"))
        }.timeout(5.seconds)
        try {
            flow.collect()
            fail("Should have thrown IllegalStateException")
        } catch (e: Exception) {
            println("exception got: $e")
            assertTrue(e is IllegalStateException, "Expected IllegalStateException but got $e")
            assertEquals("Test Exception", e.message)
        }
    }
}
"}

